nauvis_biter_base_steamrolled.init:
local surface = game.surfaces.nauvis
local logo = surface.find_entities_filtered{name = "factorio-logo-11tiles"}[1]
game.simulation.camera_position = {logo.position.x, logo.position.y+9.75}
center = {logo.position.x, logo.position.y+9.75}
game.simulation.camera_zoom = 1
game.tick_paused = false
surface.daytime = 0
game.forces.enemy.set_evolution_factor(0.3)
surface.peaceful_mode = true

local count = 120
script.on_nth_tick(2,
  function()
    count = count - 2
    if count <= 0 then
      for i=0,20 do
        local y = game.simulation.camera_position.y - 20 + i * 2
        local x = game.simulation.camera_position.x - 40
        local character = surface.create_entity{ name = "character", position = {x, y}, force = "player" }
        character.color = {1, 0, 0, 0.5}
        local tank = surface.create_entity{ name = "tank", position = {x, y}, force = "player" }
        tank.orientation = 0.25
        tank.insert{name = "rocket-fuel", count = 3}
        tank.speed = 0.5
        tank.set_driver(character)
        character.riding_state = { acceleration = defines.riding.acceleration.accelerating, direction = defines.riding.direction.straight }
      end
      script.on_nth_tick(2, nil)
    end
  end)

local wube_logo_position = {-499.5, 43.5}

script.on_nth_tick(1,
function()
  if surface.count_entities_filtered{position = wube_logo_position, radius = 3, name = "tank"} > 0 then
    local tiles = {}
    for x=-3,3 do
      for y=-3,3 do
        table.insert(tiles, {name = "dirt-1", position = {wube_logo_position[1] + x, wube_logo_position[2] + y}})
      end
    end
    surface.set_tiles(tiles)
  end
end)

nauvis_chase_player.init:
local logo = game.surfaces.nauvis.find_entities_filtered{name = "factorio-logo-11tiles", limit = 1}[1]
local center = {logo.position.x, logo.position.y+9.75}
game.simulation.camera_position = center
game.simulation.camera_zoom = 1
game.tick_paused = false
game.surfaces.nauvis.daytime = 0
game.map_settings.steering.moving.force_unit_fuzzy_goto_behavior = true
game.map_settings.steering.moving.radius = 1

local character = game.surfaces[1].create_entity{name = "character", position = {center[1] - 55, center[2] + 4.5}, force = "player"}
character.walking_state = {walking = true, direction = defines.direction.east}
character.character_running_speed_modifier = 0.2
character.tick_of_last_attack = game.tick

local biter = game.surfaces[1].create_entity{name = "small-biter", position = {center[1] - 40, center[2] + 4.5}}
biter.speed = character.character_running_speed
biter.commandable.set_command{type = defines.command.go_to_location, destination = {center[1] + 60, center[2] + 4.5}, distraction = defines.distraction.none}

script.on_nth_tick(10, function()
  if biter.position.x < (center[1] + 50) then return end
  character.walking_state = {walking = true, direction = defines.direction.west}
  character.tick_of_last_attack = 0
  character.character_running_speed_modifier = 0.6
  local command = {type = defines.command.go_to_location, destination_entity = character, distraction = defines.distraction.none}
  biter.commandable.set_command(command)
  biter.speed = character.character_running_speed
  local position = biter.position
  local surface = game.surfaces[1]
  local names = {"medium-biter", "small-biter", "small-biter", "small-biter"}
  for k = 1, 25 do
    local spawn_position = {position.x + math.random(-5, 5), position.y + math.random(-10, 10)}
    local name = names[math.random(#names)]
    local biter = surface.create_entity{name = name, position = position}
    biter.commandable.set_command(command)
    biter.speed = character.character_running_speed
  end
  script.on_nth_tick(10, nil)
end)

vulcanus_crossing.init:
  local sim_planet = game.surfaces["vulcanus"]
  local logo = sim_planet.find_entities_filtered{name = "factorio-logo-11tiles", limit = 1}[1]
  logo.destructible = false
  local center = {logo.position.x, logo.position.y+9.75}
  game.simulation.camera_surface_index = sim_planet.index
  game.simulation.camera_position = center
  game.simulation.camera_zoom = 1
  game.tick_paused = false
    local tick = 0
local on_tick = function() end
script.on_nth_tick(1,
  function()
    tick = tick + 1
    on_tick()
  end)
  game.forces.player.reset()
game.forces.player.character_health_bonus = 300000
game.forces.enemy.technologies["weapon-shooting-speed-3"].researched = true;
game.forces.enemy.technologies["weapon-shooting-speed-4"].researched = true;
game.forces.enemy.technologies["weapon-shooting-speed-5"].researched = true;
game.forces.enemy.technologies["weapon-shooting-speed-6"].researched = true;
game.forces.enemy.character_health_bonus = 300000

local second_lock = game.surfaces.vulcanus.find_entities_filtered{name = "constant-combinator", limit = 1}[1].get_control_behavior()
local character = game.surfaces.vulcanus.find_entities_filtered{name = "character", force = "player", limit = 1}[1]
character.walking_state = {walking = true, direction = defines.direction.southeast}
character.character_running_speed_modifier = -0.25

local demoman = game.surfaces.vulcanus.find_entities_filtered{name = "small-demolisher", limit = 1}[1]

local bait = game.surfaces.vulcanus.find_entities_filtered{name = "character", force = "enemy", limit = 1}[1]
bait.position.y = 2 + bait.position.y

on_tick = function()
  if tick == 100 and character.valid then
    character.walking_state = {walking = true, direction = defines.direction.south}
  end
  if tick == 155 and character.valid  then
    character.walking_state = {walking = false}
  end
  if tick == 340 and character.valid then
    character.walking_state = {walking = true, direction = defines.direction.south}
    character.character_running_speed_modifier = -0.5
  end
  if tick == 370 and bait.valid then
    bait.walking_state = {walking = true, direction = defines.direction.east}
    bait.walking_state.character_running_speed_modifier = -0.8
  end
  if tick == 400 then
    if (second_lock.valid) then
      second_lock.enabled = true
    end
    if (character.valid) then
      character.character_running_speed_modifier = -0.6
    end
    if (bait.valid) then
      bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
    end
  end
  if tick == 450 and bait.valid then
    bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
  end
  if tick == 455 and character.valid then
    character.walking_state = {walking = false}
    character.character_running_speed_modifier = -0.25
  end
  if tick == 500 and bait.valid then
    bait.shooting_state = {}
    bait.walking_state.character_running_speed_modifier = 0.0
    bait.walking_state = {walking = true, direction = defines.direction.east}
  end
  if tick == 550 and bait.valid then
    bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
  end
  if tick == 600 and bait.valid then
    bait.walking_state = {walking = true, direction = defines.direction.east}
    bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
    game.surfaces.vulcanus.create_entity{name = "poison-capsule", position = bait.position, speed = 0.3, target = demoman.position, force = "enemy"}
  end
  if tick == 750 and bait.valid then
    bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
  end
  if tick == 700 and bait.valid then
    bait.shooting_state = {}
    bait.walking_state.character_running_speed_modifier = -0.5
    bait.walking_state = {walking = true, direction = defines.direction.east}
  end
  if tick == 850 and bait.valid then
    bait.shooting_state = {}
    bait.walking_state.character_running_speed_modifier = -0.3
    game.surfaces.vulcanus.create_entity{name = "destroyer-capsule", position = bait.position, speed = 0.3, target = demoman.position, force = "enemy"}
    bait.walking_state = {walking = true, direction = defines.direction.northeast}
  end
  if tick == 900 and bait.valid then
    bait.shooting_state = {state = defines.shooting.shooting_enemies, position = demoman.position}
    bait.walking_state.character_running_speed_modifier = 0.0
    bait.walking_state = {walking = true, direction = defines.direction.southeast}
  end
end
